    private void OnFetchComplete(string raw, string source)
    {
        var res = JsonConvert.DeserializeObject<KtaneResponse>(raw);
        s_repoData = res.Modules;
        s_hasFetchedRepo = true;
        s_isFetchingRepo = false;
        s_repoEvent?.Invoke();
        Log($"Loaded data (Modules: {s_repoData.Length}, Source: {source})");
        LogLower($"Pool of mods to choose from: {s_repoData.Where(RepoFilter).Select(m => $"{m.Name} ({m.ModuleId})").Join(", ")}");
    }

    private IEnumerator DoFetchRepo()
    {
        if (s_isFetchingRepo)
            yield break;

        s_isFetchingRepo = true;

        // if present, we use the tweaks backup! unless it's over a week old. then we don't want it.

        var backupPath = Path.Combine(Application.persistentDataPath, "RepositoryBackup.json");
        if (File.Exists(backupPath) && File.GetLastWriteTime(backupPath) > DateTime.Now.AddDays(-7))
        {
            try
            {
                OnFetchComplete(File.ReadAllText(backupPath, Encoding.UTF8), "TweaksBackup");
                yield break;
            }
            catch (Exception e)
            {
                Log($"Failed to load Tweaks repository backup: {e}");
            }
        }

        using (var req = UnityWebRequest.Get(_repoUrl))
        {
            yield return req.SendWebRequest();

            if (req.isHttpError || req.isNetworkError)
            {
                Log($"Failed to load repository data from {_repoUrl}: [{req.responseCode}] {req.error}");
            }
            else
            {
                OnFetchComplete(req.downloadHandler.text, "Fetch");
            }
        }
    }

    private void WaitForRepo()
    {
        if (s_hasFetchedRepo)
        {
            OnRepoFetched();
            return;
        }

        if (!s_hasFetchedRepo || s_isFetchingRepo)
            s_repoEvent += OnRepoFetched;

        if (!s_hasFetchedRepo && !s_isFetchingRepo)
            StartCoroutine(DoFetchRepo());
    }

    private static bool IsFakeModule(BombComponent component)
    {
        // tweaks conveniently adds a ModSource to fake modules (in alignment with real module standards) and puts its own name in the field. so that's helpful
        var source = component.GetComponent<ModSource>();
        return source && source.ModName == "Tweaks";
    }

    private bool SetNextComponent(BombComponent component, float countdownTime = -1f)
    {
        // a series of final checks to ensure the component meets at least the most critical requirements

        if (!component)
        {
            Log("Failed to set next component: null");
            return false;
        }

        if (!component.IsSolvable)
        {
            Log($"Failed to set next component: {component} is not solvable!");
            return false;
        }

        if (IsFakeModule(component))
        {
            Log($"Failed to set next component: {component} is a Tweaks proxy module!");
            return false;
        }

        // then we assign the nextcomponent field

        _isPreloading = false;
        _nextComponent = component;
        _nextCountdownTime = countdownTime > 0f ? countdownTime : _needy.CountdownTime;

        // and the rest of this is just getting the mod id in order to log it

        string name = _nextComponent.ComponentType.ToString();
        var modComponent = _nextComponent.GetComponent<ModBombComponent>();
        if (modComponent)
            name = modComponent.GetModComponentType();

        LogLower($"Set next component: {name} ({_nextComponent.GetModuleDisplayName()})");

        return true;
    }

    private bool RepoFilter(KtaneModule mod)
    {
        if (!string.IsNullOrEmpty(mod.TranslationOf)) return false;
        if (mod.Type != "Regular") return false;
        if (mod.Origin != "Mods") return false;
        if (s_blacklistedMods.Contains(mod.ModuleId)) return false;
        if (_modConfig.HasWhitelist && !_modConfig.WhitelistModIds.Contains(mod.ModuleId)) return false;
        // if (!s_whitelistedDifficulties.Contains(mod.DefuserDifficulty)) return false;
        // if (!s_whitelistedDifficulties.Contains(mod.ExpertDifficulty)) return false;
        // if (!((mod.TwitchPlays != null && mod.TwitchPlays.Score <= 5) || (mod.DefuserDifficulty == "Trivial" && mod.ExpertDifficulty == "Trivial"))) return false;
        if (mod.TwitchPlays == null) return false;
        if (mod.TwitchPlays.Score > 5) return false;
        // boss condition feels unnecessary with the quirks condition, though as of writing this there are 2 modules that have a boss status but no quirks (however one is a needy and one has a TP score of 9 so they're irrelevant regardless) but nevertheless i will just leave this condition here just to be safe
        if (mod.BossStatus == "FullBoss" || mod.BossStatus == "SemiBoss") return false;
        if (!string.IsNullOrEmpty(mod.Quirks)) return false;
        return true;
    }

    private void Preload() => StartCoroutine(PreloadMod());

    // okay 4:00 am julie here. this is the main mod loading code. most of it is really truly just DBML stuff. without DBML this would be so much simpler.
    private IEnumerator PreloadMod()
    {
        // prevent double preload
        if (_isPreloading)
            yield break;

        LogLower("Preloading...");

        _isPreloading = true;
        _nextComponent = null;
        _nextCountdownTime = _needy.CountdownTime;

        // display the tester module if it is currently bundled
        if (ModManager.Instance.loadedBombComponents.ContainsKey("InjectorTester") && SetNextComponent(ModManager.Instance.loadedBombComponents["InjectorTester"]))
            yield break;

        if (s_repoData != null)
        {
            // loadedBombComponents INCLUDES unloaded dbml modules btw. tweaks just sticks a bunch of fake modules in there to trick the game
            var loaded = ModManager.Instance.loadedBombComponents;

            // a list of "applicable" mods that are also loaded
            var overlap = s_repoData.Where(RepoFilter).Where(m => loaded.ContainsKey(m.ModuleId));

            if (overlap.Any())
            {
                var repoMod = overlap.PickRandom();
                LogLower($"Selected {repoMod.ModuleId} ({repoMod.Name})");

                var timeCandidate = repoMod.TwitchPlays != null ? 45f + (float)repoMod.TwitchPlays.Score * 15f : _needy.CountdownTime;

                var loadedComponent = loaded[repoMod.ModuleId];
                if (IsFakeModule(loadedComponent))
                {
                    LogLower($"{repoMod.ModuleId} is a proxy Tweaks module, loading real module...");
                    if (repoMod.SteamId == null)
                    {
                        LogLower($"{repoMod.ModuleId} has no Steam ID! Unable to load.");
                    }
                    else
                    {
                        // so this is basically just what Tweaks does for dbml but a little simpler

                        var workshopPath = ReflectionHelper.FindType("Utilities", "TweaksAssembly")
                            .GetValue<string>("SteamWorkshopDirectory");

                        var modPath = Path.Combine(workshopPath, repoMod.SteamId);
                        LogLower($"Loading mod at {modPath}");

                        // LoadMod = load the mod info json, plus the mod settings and assemblies if the mod info json loads successfully
                        var mod = Mod.LoadMod(modPath, ModSourceEnum.Local);

                        if (mod == null)
                        {
                            Log($"Failed to load mod at {modPath}");
                        }
                        else
                        {
                            yield return StartCoroutine(ModManager.Instance.LoadModAssetBundles(mod));

                            mod.RemoveMissions();
                            mod.RemoveSoundOverrides();

                            foreach (var service in mod.GetModObjects<ModService>())
                            {
                                var serviceObj = Instantiate(service.gameObject);
                                serviceObj.transform.parent = ModManager.Instance.transform;
                                mod.AddServiceObject(serviceObj);
                            }

                            // i genuinely have NO IDEA why tweaks doesn't add loaded bomb components to loadedBombComponents. because it's skipping the part of the game code that does it. and then doesn't do it itself. because then like EVERY TIME you load a module that you ALREADY loaded before with DBML it STILL HAS TO GO THROUGH DBML so it'll say "loading X mods" for like a frame or two while it checks its OWN LIST OF MODS instead of just letting the game natively find it! i just dont understand it!!!! but I AM adding loaded bomb components to loadedBombComponents (see below) because that makes sense and it works wonderfully!!

                            foreach (var module in mod.GetModObjects<KMBombModule>())
                                loaded[module.ModuleType] = module.GetComponent<BombComponent>();

                            foreach (var module in mod.GetModObjects<KMNeedyModule>())
                                loaded[module.ModuleType] = module.GetComponent<BombComponent>();

                            ModManager.Instance.loadedMods[modPath] = mod;

                            if (loaded.ContainsKey(repoMod.ModuleId))
                            {
                                var newLoadedComponent = loaded[repoMod.ModuleId];
                                // set component
                                if (SetNextComponent(newLoadedComponent, timeCandidate))
                                    yield break;
                            }
                            else
                            {
                                // akin to Tweaks' "unable to load the module for [module id] ([steam id])"
                                Log($"Mod {mod.ModID} does NOT contain module {repoMod.ModuleId}! (after loading through DBML!) what is this witchcraft!");
                            }
                        }
                    }
                }
                else
                {
                    // set component
                    if (SetNextComponent(loadedComponent, timeCandidate))
                        yield break;
                }
            }
        }

        Log("Unable to load any modded modules. Falling back to vanilla modules.");

        var compType = s_trivialVanillas.PickRandom();
        Log($"Selected vanilla module: {compType}");

        var prefab = Prefabs.Instance.BombGenerator.componentPrefabs.FirstOrDefault(comp => comp.ComponentType == compType);
        // set component
        if (SetNextComponent(prefab))
            yield break;

        _isPreloading = false;
        Log("Unable to load vanilla fallback. (this should NEVER happen! please report this to the mod author!)");
    }

