    private static bool TryGetModuleId(Component mod, out int id)
    {
        foreach (var comp in mod.GetComponents<Component>())
        {
            if (!comp)
                continue;

            var res = new Dictionary<string, int>();

            // this concept is pulled from Tweaks but just kinda simplified. it doesn't have to be perfect, it's just helpful for better logging

            var type = comp.GetType();
            var flags = BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance;

            foreach (var field in type.GetAllFields(flags))
                if (field.FieldType == typeof(int))
                    res[field.Name] = (int)field.GetValue(comp);

            foreach (var prop in type.GetAllProperties(flags))
                if (prop.PropertyType == typeof(int))
                    res[prop.Name] = (int)prop.GetValue(comp, null);

            foreach (var pair in res)
                if (Regex.IsMatch(pair.Key, "(mod|log).*(id|num)", RegexOptions.IgnoreCase))
                {
                    id = pair.Value;
                    return true;
                }
        }

        id = 0;
        return false;
    }

    private string GetLoggingTag()
    {
        if (_instantiatedComponent)
        {
            // should never be needy but just in case
            if (_instantiatedComponent.ComponentType == ComponentTypeEnum.Mod || _instantiatedComponent.ComponentType == ComponentTypeEnum.NeedyMod)
            {
                int id;
                if (TryGetModuleId(_instantiatedComponent, out id))
                {
                    return $"{_instantiatedComponent.GetModuleDisplayName()} #{id}";
                }
            }
            else
            {
                // vanilla modules have a proper log4net logger so we can just pull the logger name (with the id and everything) directly
                return _instantiatedComponent.logger.Logger.Name;
            }
        }

        return null;
    }

    private void TryMatchLog(string message)
    {
        if (_nestedTag != null && _instantiatedComponent)
        {
            string fullTag = $"[{_nestedTag}] ";
            if (message != null && message.StartsWith(fullTag))
            {
                var body = message.Substring(fullTag.Length);
                Log($"[{_instantiatedComponent.GetModuleDisplayName()}] {body}");
            }
        }
    }

    private void OnLogMessage(string logString, string stackTrace, LogType type)
    {
        // when something gets logged:

        // we add it to the log queue in case we determine the logging id later down the line and need to pull older logs with that tag to display them in LFA
        _logQueue.Add(logString);

        // and we also see if it matches the active logging tag, when applicable
        TryMatchLog(logString);
    }

